instantiations.instance:
// Arbitrate between all simultaneously valid error log requests.
prim_racl_error_arb #(
  .N ( 2 )
) u_prim_err_arb (
  .clk_i,
  .rst_ni,
  .error_log_i ( racl_error   ),
  .error_log_o ( racl_error_o )
);

// SEC_CM: CTRL.CONFIG.REGWEN
// SEC_CM: EXEC.CONFIG.REGWEN
// SEC_CM: READBACK.CONFIG.REGWEN
sram_ctrl_regs_reg_top #(
  .EnableRacl       ( EnableRacl           ),
  .RaclErrorRsp     ( RaclErrorRsp         ),
  .RaclPolicySelVec ( RaclPolicySelVecRegs )
) u_reg_regs (
  .clk_i,
  .rst_ni,
  .tl_i             ( regs_tl_i          ),
  .tl_o             ( regs_tl_o          ),
  .reg2hw,
  .hw2reg,
  // RACL interface
  .racl_policies_i  ( racl_policies_i    ),
  .racl_error_o     ( racl_error[0]      ),
  // SEC_CM: BUS.INTEGRITY
  .intg_err_o       ( bus_integ_error[0] )
 );

// We employ two redundant counters to guard against FI attacks.
// If any of the two is glitched and the two counter states do not agree,
// we trigger an alert.
// SEC_CM: INIT.CTR.REDUN
prim_count #(
  .Width(AddrWidth)
) u_prim_count (
  .clk_i,
  .rst_ni,
  .clr_i(init_trig),
  .set_i(1'b0),
  .set_cnt_i('0),
  .incr_en_i(init_req),
  .decr_en_i(1'b0),
  .step_i(AddrWidth'(1)),
  .commit_i(1'b1),
  .cnt_o(init_cnt),
  .cnt_after_commit_o(),
  .err_o(init_error)
);
